const ctx = {
  workflow_name:    'collector-openai',
  source_slug:      'openai-blog',
  collector_version:'1.0.0',
  pipeline_version: '1.0.0',
  run_id:           `run_${Date.now()}`,
  started_at:       new Date().toISOString(),
  max_items:        20,
};
console.log('[START]', JSON.stringify(ctx));
return [{ json: { _ctx: ctx } }];

// Respect max_items from context
const ctx = $('Set Workflow Context').first().json._ctx;
const all = $input.all();
const limited = all.slice(0, ctx.max_items || 20);
console.log(`[FETCH] got=${all.length} processing=${limited.length}`);
return limited;

// ── NORMALIZE (inline from shared/normalize.js) ───────────────
function normalizeUrl(url) {
  if (!url) return '';
  try {
    const u = new URL(String(url).trim());
    ['utm_source','utm_medium','utm_campaign','ref'].forEach(p => u.searchParams.delete(p));
    return u.href;
  } catch { return String(url).trim(); }
}
function normalizeDate(v) {
  if (!v) return null;
  try { const d = new Date(v); return isNaN(d.getTime()) ? null : d.toISOString(); } catch { return null; }
}
function normalizeTags(t) {
  if (!t) return [];
  return (Array.isArray(t) ? t : String(t).split(','))
    .map(s => s.trim().toLowerCase().replace(/\s+/g,'-').replace(/[^a-z0-9-]/g,''))
    .filter(s => s.length > 0 && s.length <= 50).slice(0,20);
}

const normalized = $input.all().map(item => {
  const raw = item.json;
  return { json: {
    title:        String(raw.title || '').trim().replace(/\s+/g,' ').slice(0,500),
    url:          normalizeUrl(raw.link || raw.url || ''),
    source_slug:  'openai-blog',
    content_raw:  String(raw.content || raw.contentSnippet || raw.description || '').slice(0,50000) || null,
    author:       String(raw.creator || raw.author || 'OpenAI').slice(0,200) || null,
    published_at: normalizeDate(raw.isoDate || raw.pubDate),
    tags:         normalizeTags(raw.categories || []),
    language:     'en',
    category_hint:'model-releases',
    external_id:  String(raw.guid || raw.link || '').slice(0,200) || null,
    metadata:     { guid: raw.guid, source_type: 'rss' },
    collected_at: new Date().toISOString(),
    url_hash:     null,
  }};
});
console.log(`[NORMALIZE] processed ${normalized.length} items`);
return normalized;

// ── VALIDATE (inline from shared/validate.js) ─────────────────
const REQUIRED = ['title','url','source_slug'];
function validate(item) {
  const errors = [];
  for (const f of REQUIRED) {
    if (!item[f] || !String(item[f]).trim()) errors.push({ field: f, error: 'required' });
  }
  if (item.url) { try { new URL(item.url); } catch { errors.push({ field:'url', error:'invalid URL' }); } }
  if (!Array.isArray(item.tags)) errors.push({ field:'tags', error:'must be array' });
  if (item.published_at) {
    const d = new Date(item.published_at);
    if (isNaN(d)) errors.push({ field:'published_at', error:'invalid date' });
    if (d > new Date()) errors.push({ field:'published_at', error:'future date' });
  }
  return { valid: errors.length === 0, errors };
}
const valid = [], invalid = [];
for (const item of $input.all()) {
  const r = validate(item.json);
  if (r.valid) valid.push(item);
  else { invalid.push(item); console.warn('[VALIDATE] rejected:', item.json.url, JSON.stringify(r.errors)); }
}
console.log(`[VALIDATE] valid=${valid.length} invalid=${invalid.length}`);
return valid;

// ── ENRICH (inline from shared/enrich.js) ─────────────────────
const ctx = $('Set Workflow Context').first().json._ctx;

function hashUrl(url) {
  const s = url.trim().toLowerCase();
  let h = 2166136261;
  for (let i = 0; i < s.length; i++) { h ^= s.charCodeAt(i); h = (h * 16777619) >>> 0; }
  return h.toString(16).padStart(8,'0');
}
function estimateReadTime(text) {
  if (!text) return 1;
  return Math.max(1, Math.round(text.trim().split(/\s+/).length / 200));
}

const enriched = $input.all().map(item => {
  const i = item.json;
  return { json: {
    ...i,
    url_hash:            hashUrl(i.url),
    language:            i.language || 'en',
    fetched_at:          new Date().toISOString(),
    estimated_read_time: estimateReadTime(i.content_raw),
    metadata: {
      ...(i.metadata || {}),
      collector_name:    ctx.workflow_name,
      collector_version: ctx.collector_version,
      pipeline_version:  ctx.pipeline_version,
      source_slug:       ctx.source_slug,
    },
  }};
});
console.log(`[ENRICH] enriched ${enriched.length} items`);
return enriched;

// ── DEDUP (inline from shared/dedup.js) ───────────────────────
const response = $('Check Existing Hashes').first().json;
const existing = new Set((response?.data?.results || []).map(r => r.url_hash).filter(Boolean));
const allItems = $('Enrich Items').all();
const withinBatch = new Set();
const newItems = [];

for (const item of allItems) {
  const h = item.json.url_hash;
  if (existing.has(h) || withinBatch.has(h)) {
    console.log('[DEDUP] skipped:', item.json.url);
  } else {
    newItems.push(item);
    withinBatch.add(h);
  }
}
console.log(`[DEDUP] new=${newItems.length} duplicates=${allItems.length - newItems.length}`);
return newItems;

const srcResponse = $('Resolve Source ID').first().json;
const source = srcResponse?.data;
const sourceId = source?.id ?? null;
if (!sourceId) console.warn('[STORE] source_id not found for slug: openai-blog');
const items = $('Filter Duplicates').all();
return items.map(item => ({ json: { ...item.json, source_id: sourceId } })).filter(i => !!i.json.source_id);

