const ctx         = $('Set Workflow Context').first().json._ctx;
const fetched     = $('Limit Items').all().length;
const validated   = $('Validate Items').all().length;
const deduplicated= $('Filter Duplicates').all().length;
const storeResults= $('Store Items').all();
const stored      = storeResults.filter(r => r.json?.success === true).length;
const storeFailed = storeResults.filter(r => r.json?.success === false).length;

const summary = {
  workflow:          ctx.workflow_name,
  source_slug:       ctx.source_slug,
  run_id:            ctx.run_id,
  started_at:        ctx.started_at,
  finished_at:       new Date().toISOString(),
  duration_ms:       Date.now() - new Date(ctx.started_at).getTime(),
  status:            storeFailed > 0 ? 'partial' : 'success',
  items_fetched:     fetched,
  items_validated:   validated,
  items_deduplicated:deduplicated,
  items_stored:      stored,
  items_skipped:     fetched - validated,
  items_duplicate:   validated - deduplicated,
  store_failures:    storeFailed,
};
console.log('[SUMMARY]', JSON.stringify(summary));
return [{ json: summary }];
